- Highly acclaimed refers to products with an average rating greater than 4; 
- Featured products are those with the is_featured flag set to 1; 
- The supreme category is assumed to be the category with a category_id of 0.

sql:
SELECT COUNT(DISTINCT o.order_id) AS total_orders
FROM orders o
JOIN reviews r ON o.product_id = r.product_id;

SELECT DISTINCT p.product_id, p.title
FROM products p
JOIN reviews r ON p.product_id = r.product_id
WHERE r.user_id = (
    SELECT user_id FROM users WHERE username = 'john_doe'
) AND p.product_id NOT IN (
    SELECT o.product_id FROM orders o
    WHERE o.user_id = (
        SELECT user_id FROM users WHERE username = 'john_doe'
    )
);

SELECT p.title
FROM products p
WHERE p.product_id NOT IN (SELECT product_id FROM orders);
